exercises.solution:
def apply_greet(name):
    def add_greet(cls):
        def greet(self):
            return 'hi, ' + self.name
        cls.greet = greet
        return cls

    @add_greet
    class C:
        def __init__(self, n):
            self.name = n

    return C(name).greet()
